import React, { useState, useEffect } from "react";
import API from "./api";

const MOODS = [
  { key: "Happy",   emoji: "😊", bg: "#EBF3EC", border: "#7A9E7E", text: "#4A6E4E" },
  { key: "Calm",    emoji: "😌", bg: "#EDE8F7", border: "#9B8EC4", text: "#5A4A8A" },
  { key: "Anxious", emoji: "😰", bg: "#FBF3E2", border: "#D4A853", text: "#8A6020" },
  { key: "Sad",     emoji: "😔", bg: "#E8F0F7", border: "#7AAAC4", text: "#3A6A8A" },
  { key: "Angry",   emoji: "😤", bg: "#F7EAEC", border: "#C4848E", text: "#8A3A44" },
];

const EMOJI_MAP = Object.fromEntries(MOODS.map(m => [m.key, m.emoji]));
const COLOR_MAP = Object.fromEntries(MOODS.map(m => [m.key, m]));

function timeAgo(dateStr) {
  const today = new Date();
  const date  = new Date(dateStr);
  const diff  = Math.floor((today - date) / 86400000);
  if (diff === 0) return "Today";
  if (diff === 1) return "Yesterday";
  return `${diff} days ago`;
}

export default function MoodLogs() {
  const [logs, setLogs]         = useState([]);
  const [selected, setSelected] = useState(null);
  const [notes, setNotes]       = useState("");
  const [saving, setSaving]     = useState(false);
  const [alert, setAlert]       = useState(null);

  useEffect(() => { fetchLogs(); }, []);

  async function fetchLogs() {
    try {
      const { data } = await API.get("mood/");
      setLogs(data.slice(0, 10));
    } catch { /* backend not running */ }
  }

  async function handleSave() {
    if (!selected) return;
    setSaving(true);
    try {
      await API.post("mood/", { mood: selected, notes });
      setAlert({ type: "success", text: "Mood logged ✓" });
      setSelected(null);
      setNotes("");
      fetchLogs();
    } catch {
      setAlert({ type: "error", text: "Could not save — is the backend running?" });
    } finally {
      setSaving(false);
      setTimeout(() => setAlert(null), 3000);
    }
  }

  const mostCommon = (() => {
    if (!logs.length) return null;
    const freq = {};
    logs.forEach(l => freq[l.mood] = (freq[l.mood] || 0) + 1);
    return Object.entries(freq).sort((a, b) => b[1] - a[1])[0]?.[0];
  })();

  return (
      <div style={styles.wrapper}>

        {/* ── LEFT: Form ── */}
        <div style={styles.formPanel}>

          {/* Stats strip */}
          <div style={styles.statsStrip}>
            <div style={styles.statItem}>
              <span style={styles.statNum}>{logs.length}</span>
              <span style={styles.statLbl}>Total logs</span>
            </div>
            <div style={styles.statDivider} />
            <div style={styles.statItem}>
              <span style={styles.statNum}>{logs[0] ? EMOJI_MAP[logs[0].mood] : "–"}</span>
              <span style={styles.statLbl}>Latest</span>
            </div>
            <div style={styles.statDivider} />
            <div style={styles.statItem}>
              <span style={styles.statNum}>{mostCommon || "–"}</span>
              <span style={styles.statLbl}>Most common</span>
            </div>
          </div>

          {/* Prompt */}
          <div style={styles.promptArea}>
            <p style={styles.promptQ}>How are you feeling right now?</p>
            <p style={styles.promptSub}>Select a mood, then add a note if you'd like.</p>
          </div>

          {/* Mood selector */}
          <div style={styles.moodRow}>
            {MOODS.map(({ key, emoji, bg, border, text }) => (
                <button
                    key={key}
                    onClick={() => setSelected(key)}
                    style={{
                      ...styles.moodBtn,
                      background: selected === key ? bg : "#fff",
                      borderColor: selected === key ? border : "rgba(42,42,38,0.12)",
                      transform: selected === key ? "translateY(-4px) scale(1.04)" : "translateY(0) scale(1)",
                      boxShadow: selected === key ? `0 8px 20px ${border}40` : "none",
                    }}
                >
                  <span style={styles.moodEmoji}>{emoji}</span>
                  <span style={{ ...styles.moodLabel, color: selected === key ? text : "#8A8680" }}>
                {key}
              </span>
                  {selected === key && (
                      <span style={{ ...styles.moodDot, background: border }} />
                  )}
                </button>
            ))}
          </div>

          {/* Notes */}
          <div style={styles.notesWrap}>
            <label style={styles.notesLabel}>
              Add a note
              <span style={styles.notesOptional}> — optional</span>
            </label>
            <textarea
                style={styles.textarea}
                placeholder="What's on your mind? Any thoughts, feelings, or context..."
                value={notes}
                onChange={e => setNotes(e.target.value)}
                onFocus={e => e.target.style.borderColor = "#7A9E7E"}
                onBlur={e => e.target.style.borderColor = "rgba(42,42,38,0.14)"}
            />
            <div style={styles.charCount}>{notes.length} / 300</div>
          </div>

          {/* Alert */}
          {alert && (
              <div style={{
                ...styles.alert,
                background: alert.type === "success" ? "#EBF3EC" : "#F7EAEC",
                borderColor: alert.type === "success" ? "#7A9E7E" : "#C4848E",
                color:       alert.type === "success" ? "#4A6E4E" : "#8A3A44",
              }}>
                {alert.text}
              </div>
          )}

          {/* Submit */}
          <button
              style={{
                ...styles.submitBtn,
                opacity: (!selected || saving) ? 0.5 : 1,
                cursor:  (!selected || saving) ? "not-allowed" : "pointer",
              }}
              onClick={handleSave}
              disabled={!selected || saving}
              onMouseEnter={e => { if (selected && !saving) e.target.style.background = "#4A6E4E"; }}
              onMouseLeave={e => { e.target.style.background = "#7A9E7E"; }}
          >
            {saving ? "Saving…" : selected ? `Log "${selected}" mood` : "Select a mood first"}
          </button>
        </div>

        {/* ── RIGHT: History ── */}
        <div style={styles.historyPanel}>
          <div style={styles.historyHeader}>
            <span style={styles.historyTitle}>Recent entries</span>
            <span style={styles.historyCount}>{logs.length} logs</span>
          </div>

          {logs.length === 0 ? (
              <div style={styles.emptyState}>
                <div style={styles.emptyIcon}>📋</div>
                <div style={styles.emptyText}>No entries yet</div>
                <div style={styles.emptySub}>Your mood history will appear here</div>
              </div>
          ) : (
              <div style={styles.logList}>
                {logs.map((log, i) => {
                  const c = COLOR_MAP[log.mood] || { bg: "#F0EDE4", border: "#C0BAB0", text: "#5A5750" };
                  return (
                      <div
                          key={log.id}
                          style={{
                            ...styles.logItem,
                            animationDelay: `${i * 0.05}s`,
                          }}
                      >
                        <div style={{ ...styles.logAccent, background: c.border }} />
                        <div style={{ ...styles.logEmojiBox, background: c.bg }}>
                          <span style={styles.logEmoji}>{EMOJI_MAP[log.mood] || "😶"}</span>
                        </div>
                        <div style={styles.logBody}>
                          <div style={styles.logMoodRow}>
                            <span style={{ ...styles.logMoodName, color: c.text }}>{log.mood}</span>
                            <span style={styles.logDate}>{timeAgo(log.date)}</span>
                          </div>
                          {log.notes
                              ? <div style={styles.logNotes}>{log.notes}</div>
                              : <div style={styles.logNoNotes}>No note added</div>
                          }
                        </div>
                      </div>
                  );
                })}
              </div>
          )}
        </div>
      </div>
  );
}

const styles = {
  wrapper: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: 28,
    alignItems: "start",
  },

  /* ── Form Panel ── */
  formPanel: {
    background: "#fff",
    borderRadius: 22,
    border: "1px solid rgba(42,42,38,0.09)",
    padding: "28px 30px",
    boxShadow: "0 1px 3px rgba(42,42,38,0.05), 0 4px 24px rgba(42,42,38,0.05)",
  },
  statsStrip: {
    display: "flex",
    alignItems: "center",
    background: "#FAF8F3",
    borderRadius: 12,
    padding: "12px 20px",
    marginBottom: 26,
    gap: 0,
  },
  statItem: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: 3,
  },
  statNum: {
    fontFamily: "'DM Serif Display', serif",
    fontSize: 20,
    color: "#2C2A26",
    lineHeight: 1,
  },
  statLbl: {
    fontSize: 10,
    fontWeight: 500,
    textTransform: "uppercase",
    letterSpacing: "0.5px",
    color: "#9A9790",
  },
  statDivider: {
    width: 1,
    height: 28,
    background: "rgba(42,42,38,0.1)",
    margin: "0 4px",
  },
  promptArea: {
    marginBottom: 22,
  },
  promptQ: {
    fontFamily: "'DM Serif Display', serif",
    fontSize: 20,
    color: "#2C2A26",
    margin: "0 0 5px",
    letterSpacing: "-0.3px",
  },
  promptSub: {
    fontSize: 13,
    color: "#9A9790",
    margin: 0,
  },

  /* Mood buttons */
  moodRow: {
    display: "grid",
    gridTemplateColumns: "repeat(5, 1fr)",
    gap: 8,
    marginBottom: 24,
  },
  moodBtn: {
    position: "relative",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: 5,
    padding: "13px 6px 10px",
    borderRadius: 12,
    border: "1.5px solid",
    cursor: "pointer",
    transition: "all 0.2s cubic-bezier(0.4,0,0.2,1)",
    outline: "none",
  },
  moodEmoji: {
    fontSize: 24,
    lineHeight: 1,
  },
  moodLabel: {
    fontSize: 10,
    fontWeight: 500,
    letterSpacing: "0.2px",
    transition: "color 0.2s",
  },
  moodDot: {
    position: "absolute",
    bottom: 6,
    width: 4,
    height: 4,
    borderRadius: "50%",
  },

  /* Notes */
  notesWrap: {
    marginBottom: 18,
  },
  notesLabel: {
    display: "block",
    fontSize: 13,
    fontWeight: 500,
    color: "#5A5750",
    marginBottom: 7,
    letterSpacing: "0.1px",
  },
  notesOptional: {
    fontWeight: 400,
    color: "#9A9790",
  },
  textarea: {
    width: "100%",
    padding: "12px 14px",
    border: "1.5px solid rgba(42,42,38,0.14)",
    borderRadius: 10,
    fontFamily: "'DM Sans', sans-serif",
    fontSize: 13,
    color: "#2C2A26",
    background: "#FAF8F3",
    resize: "none",
    minHeight: 90,
    lineHeight: 1.6,
    outline: "none",
    transition: "border-color 0.2s, box-shadow 0.2s",
    boxSizing: "border-box",
  },
  charCount: {
    textAlign: "right",
    fontSize: 11,
    color: "#9A9790",
    marginTop: 4,
  },

  /* Alert */
  alert: {
    padding: "10px 14px",
    borderRadius: 8,
    fontSize: 13,
    border: "1px solid",
    marginBottom: 14,
  },

  /* Submit */
  submitBtn: {
    width: "100%",
    padding: "12px 20px",
    background: "#7A9E7E",
    color: "#fff",
    border: "none",
    borderRadius: 10,
    fontFamily: "'DM Sans', sans-serif",
    fontSize: 14,
    fontWeight: 500,
    transition: "background 0.2s, transform 0.15s",
    letterSpacing: "0.1px",
  },

  /* ── History Panel ── */
  historyPanel: {
    background: "#fff",
    borderRadius: 22,
    border: "1px solid rgba(42,42,38,0.09)",
    padding: "28px 30px",
    boxShadow: "0 1px 3px rgba(42,42,38,0.05), 0 4px 24px rgba(42,42,38,0.05)",
  },
  historyHeader: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    marginBottom: 20,
    paddingBottom: 16,
    borderBottom: "1px solid rgba(42,42,38,0.08)",
  },
  historyTitle: {
    fontFamily: "'DM Serif Display', serif",
    fontSize: 18,
    color: "#2C2A26",
    letterSpacing: "-0.3px",
  },
  historyCount: {
    fontSize: 12,
    fontWeight: 500,
    color: "#9A9790",
    background: "#FAF8F3",
    padding: "3px 10px",
    borderRadius: 99,
    border: "1px solid rgba(42,42,38,0.08)",
  },
  logList: {
    display: "flex",
    flexDirection: "column",
    gap: 10,
  },
  logItem: {
    display: "flex",
    alignItems: "center",
    gap: 12,
    padding: "12px 14px",
    background: "#FAF8F3",
    borderRadius: 12,
    border: "1px solid rgba(42,42,38,0.07)",
    position: "relative",
    overflow: "hidden",
    animation: "fadeIn 0.3s ease forwards",
    opacity: 0,
  },
  logAccent: {
    position: "absolute",
    left: 0,
    top: 0,
    bottom: 0,
    width: 3,
    borderRadius: "12px 0 0 12px",
  },
  logEmojiBox: {
    width: 38,
    height: 38,
    borderRadius: 10,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    flexShrink: 0,
  },
  logEmoji: {
    fontSize: 20,
  },
  logBody: {
    flex: 1,
    minWidth: 0,
  },
  logMoodRow: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    marginBottom: 2,
  },
  logMoodName: {
    fontSize: 13,
    fontWeight: 500,
  },
  logDate: {
    fontSize: 11,
    color: "#9A9790",
    flexShrink: 0,
  },
  logNotes: {
    fontSize: 12,
    color: "#5A5750",
    whiteSpace: "nowrap",
    overflow: "hidden",
    textOverflow: "ellipsis",
    lineHeight: 1.4,
  },
  logNoNotes: {
    fontSize: 12,
    color: "#C0BAB0",
    fontStyle: "italic",
  },

  /* Empty */
  emptyState: {
    textAlign: "center",
    padding: "48px 20px",
  },
  emptyIcon: {
    fontSize: 32,
    marginBottom: 10,
    opacity: 0.4,
  },
  emptyText: {
    fontSize: 15,
    fontWeight: 500,
    color: "#8A8680",
    marginBottom: 4,
  },
  emptySub: {
    fontSize: 12,
    color: "#9A9790",
  },
};
